function GMHelper:resetADTimes(player)
    player.free_upgrade_time = tostring(0)
    GameLicense:updatePlayerData(player)
    player.free_gift_refresh_time = tostring(0)
    WatchADHelper:synWatchAdData(player)
    player.challenge_ad = true
    TreasureChallenge:resetTreasureAd(player)
end